B.bE=new A.iA(0,"none")
B.a6m=new A.dy("Welcome!","This app teaches you how to build **finite automata**, **pushdown automata**, and **Turing machines** \u2014 the fundamental models of computation.\n\nEach level asks you to build an automaton that matches a target language. Follow these tutorials first to learn the tools, then dive in!",B.bE)
B.a69=new A.iA(1,"addNode")
B.a6l=new A.dy("Adding States","**Double-tap** on any empty area of the canvas to create a new state (circle).\n\nStates represent positions your machine can be in while reading input. You can drag states around to arrange your diagram.",B.a69)
B.a6b=new A.iA(2,"addTransition")
B.a6B=new A.dy("Drawing Transitions",'Hold **Shift** and drag from one state to another to draw a transition arrow.\n\nAfter drawing, **tap the label** on the arrow to set which input symbol it reads (e.g. "a", "b", "0", "1"). A single arrow can carry multiple symbols \u2014 separate them with commas.',B.a6b)
B.a6c=new A.iA(3,"setAccepting")
B.a6w=new A.dy("Accept States",'A state shown with a **double ring** is an accepting state \u2014 the machine accepts the input if it finishes in one of these.\n\nTo make a state accepting: **tap it** to open its menu, then toggle **"Accept"**.',B.a6c)
B.a6d=new A.iA(4,"setStartArrow")
B.a6j=new A.dy("The Start Arrow","Every automaton needs exactly **one start state** \u2014 the state it begins in.\n\nDrag the floating start arrow onto a state to set it as the start. If no start arrow is visible, use the **toolbar** to place one.",B.a6d)
B.a6i=new A.iA(9,"deleteMode")
B.a6C=new A.dy("Deleting Things","Made a mistake? Use the **trash-can** button in the toolbar to enter delete mode.\n\nIn delete mode, **tap** any state or transition arrow to remove it. Tap the trash-can again to exit delete mode.",B.a6i)
B.a6a=new A.iA(10,"checkAnswer")
B.a6r=new A.dy("Checking Your Answer",'When you think your automaton is correct, tap **"Check"** in the top-right corner.\n\nThe app will test your machine against the target language. If they match, the level is complete! If not, you\'ll see a **counterexample** \u2014 a string your machine handles differently from the target.',B.a6a)
B.Qf=s([B.a6m,B.a6l,B.a6B,B.a6w,B.a6j,B.a6C,B.a6r],t.nY)
B.L=new A.EF(0,"buildAutomaton")
B.Md=new A.aM("tutorial_welcome","How to Play","Learn the basics of the automata canvas.","",B.D,null,B.be,B.GJ,0.5,"tutorial",!0,B.Qf,null,B.L,"",!1)
