B.Mr=new A.aM("dsl_only_empty_nfa","Only \u2205 (NFA)","Build an NFA that accepts only the empty string \u2205 and rejects every non-empty input.","      n0 = A\n      n0 = (607.3, 408.0)\n      n0 is accepted\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.bA,B.a5,B.jZ,0.2,"nfa",!1,B.H,null,B.L,"",!1)
B.N2=new A.aM("dsl_accepts_everything_nfa","Accept Everything (NFA)",'Build a two-state NFA that uses a free \u03b5-jump to accept every string. Hint: an \u03b5-transition (no label) is a "free jump" to another state.',"      n0 = A\n      n1 = B\n      n0 = (734.0, 447.3)\n      n1 = (1022.0, 468.7)\n      n1 is accepted\n      n0 to n1\n      n1 to n1 = .\n      . loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.bA,B.a5,B.jZ,0.4,"nfa",!1,B.H,null,B.L,"",!1)
