B.Nd=new A.aM("dfa_starts_a",'Starts with "a" (DFA)','Build a DFA over {a, b} that accepts all strings that start with "a". Every state must handle both symbols.',"      n0 = A\n      n1 = B\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 600.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n1 = a,b\n      n2 to n2 = a,b\n      l2(a,b) loop angle = -1.5708\n      l3(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.az,B.a5,B.D4,0.65,"dfa",!1,B.H,null,B.L,"",!1)
