B.Mi=new A.aM("dsl_binary_mod7","Binary Mod 7","Build a DFA over {0,1} that accepts binary strings whose value is divisible by 7 (binary mod 7 = 0). States 0\u20136 represent the current remainder.","      n0 = 0\n      n1 = 1\n      n2 = 2\n      n3 = 3\n      n4 = 4\n      n5 = 5\n      n6 = 6\n      n0 = (640.0, 92.6)\n      n1 = (1112.0, 196.0)\n      n2 = (1560.0, 282.7)\n      n3 = (250.0, 223.3)\n      n4 = (929.3, 422.7)\n      n5 = (645.3, 592.7)\n      n6 = (303.3, 518.7)\n      n0 is accepted\n      n0 to n1 = 1\n      n0 to n0 = 0\n      n1 to n2 = 0\n      n1 to n3 = 1\n      n3 to n6 = 0\n      n3 to n0 = 1\n      n2 to n5 = 1\n      n2 to n4 = 0\n      n4 to n1 = 0\n      n4 to n2 = 1\n      n5 to n3 = 1\n      n5 to n4 = 1\n      n6 to n5 = 0\n      n6 to n6 = 1\n      l3(1) curve = 21.0\n      l4(0) curve = -194.4\n      l5(1) curve = 34.0\n      l6(1) curve = 316.5\n      l7(0) curve = 152.5\n      l8(0) curve = 17.9\n      l9(1) curve = -15.5\n      l10(1) curve = 15.0\n      l11(1) curve = -59.2\n      l1(0) loop angle = -1.5708\n      l13(1) loop angle = -1.5708\n      to n0\n      to n0 length = 150.3\n      to n0 angle = -0.8423, -0.5390\n    ",B.D,null,B.cP,B.D6,0.25,"boss",!1,B.H,null,B.L,"",!1)
B.MZ=new A.aM("dsl_binary_mod8","Binary Mod 8","Build a DFA over {0,1} that accepts binary strings whose value is divisible by 8 (binary mod 8 = 0). States 0\u20137 represent the current remainder.","      n0 = 0\n      n1 = 1\n      n2 = 2\n      n3 = 3\n      n4 = 4\n      n5 = 5\n      n6 = 6\n      n7 = 7\n      n0 = (338.0, 209.3)\n      n1 = (715.3, 212.0)\n      n2 = (432.0, 446.7)\n      n3 = (1418.7, 219.3)\n      n4 = (167.3, 640.7)\n      n5 = (585.3, 610.0)\n      n6 = (870.0, 627.3)\n      n7 = (1173.3, 622.0)\n      n0 is accepted\n      n0 to n0 = 0\n      n0 to n1 = 1\n      n1 to n3 = 1\n      n1 to n2 = 0\n      n2 to n4 = 0\n      n4 to n0 = 0\n      n4 to n1 = 1\n      n2 to n5 = 1\n      n5 to n2 = 0\n      n5 to n3 = 1\n      n3 to n6 = 0\n      n3 to n7 = 1\n      n7 to n6 = 0\n      n7 to n7 = 1\n      n6 to n4 = 0\n      n6 to n5 = 1\n      l6(1) curve = 439.5\n      l7(1) curve = 30.8\n      l8(0) curve = 16.7\n      l14(0) curve = 126.4\n      l0(0) loop angle = -1.5708\n      l13(1) loop angle = 0.4628\n      to n0\n      to n0 length = 114.5\n      to n0 angle = -0.9767, -0.2148\n    ",B.D,null,B.cP,B.D6,0.75,"boss",!1,B.H,null,B.L,"",!1)
B.QY=s(["dsl_binary_mod7","dsl_binary_mod8"],t.s)
B.Yc=new A.hM(B.QY)
B.a6g=new A.iA(7,"pdaStack")
B.a6F=new A.dy("Beyond Finite Memory","Some languages **cannot** be recognised by a DFA or NFA. The classic example is a\u207fb\u207f \u2014 equal numbers of a's then b's.\n\nA DFA has no memory of how many a's it has seen. A **PDA** adds a **stack** \u2014 an infinite scratchpad \u2014 which solves this.",B.a6g)
B.a6G=new A.dy("PDA Transition Format",'Each PDA transition arrow has the label format:\n\n  **read, pop | push**\n\n\u2022 **read** \u2014 the input symbol consumed (**~** means consume nothing)\n\u2022 **pop**  \u2014 the stack symbol removed from the top (**~** means pop nothing)\n\u2022 **push** \u2014 the stack symbol added on top (**~** means push nothing)\n\nExample: **"a, ~ | X"** \u2014 read "a", don\'t pop, push "X".',B.bE)
B.a6t=new A.dy("Stack Strategy for a\u207fb\u207f",'Here\'s the classic approach for equal-count problems:\n\n1. **Push** a marker (e.g. X) for each "a" you read.\n2. When you start reading "b"s, **pop** one X per "b".\n3. Accept when the stack is empty and input is exhausted.\n\nIf the stack runs out before the input (or vice versa), the counts don\'t match \u2014 reject.',B.bE)
B.Qk=s([B.a6F,B.a6G,B.a6t],t.nY)
B.MO=new A.aM("tutorial_pda","Pushdown Automata","Learn how PDAs use a stack to recognise context-free languages.","",B.D,null,B.be,B.Yc,0.5,"tutorial",!0,B.Qk,null,B.L,"",!1)
B.Ug={'"Green Leaf"':0,"(others)":1}
B.ZE=new A.dO(B.Ug,2,t.l)
B.D8=new A.ca("tutorial_pda")
B.Mm=new A.aM("dsl_caterpillar_nfa","Hungry Caterpillar (NFA)",'The Very Hungry Caterpillar ends by eating EXACTLY one "Green Leaf".\nBuild an NFA over story words where .-"Green Leaf" means "every word except Green Leaf". Accept strings whose last food item is exactly one Green Leaf.','      n0 = A\n      n1 = B\n      n0 = (689.3, 458.7)\n      n1 = (1080.7, 454.7)\n      n1 is accepted\n      n0 to n1 = "Green Leaf"\n      n0 to n0 = .-"Green Leaf"\n      .-"Green Leaf" loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ',B.D,B.bA,B.ZE,B.D8,0.2,"nfa",!1,B.H,null,B.L,"",!1)
B.UB={a:0,b:1,c:2,"\u2026":3,z:4}
B.ZM=new A.dO(B.UB,5,t.l)
B.Mg=new A.aM("dsl_halt_accept_y","Halt on y",'Build an FA over the lowercase English alphabet that stops computing and accepts the moment it sees the letter "y".\nUse <<Ha>> to mark a halt-and-accept state, and .-y to mean "every letter except y".',"      n0 = A\n      n1 = <<Ha>>\n      n0 = (484.0, 492.0)\n      Ha = (834.0, 492.0)\n      n0 to Ha = y\n      n0 to n0 = a,b,c,d,e,f,g,h,i,j,k,l,m,n,o,p,q,r,s,t,u,v,w,x,z\n      a,b,c,d,e,f,g,h,i,j,k,l,m,n,o,p,q,r,s,t,u,v,w,x,z loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.ZM,B.D8,0.8,"fa",!1,B.H,null,B.L,"",!1)
B.Um={"(":0,")":1}
B.ZJ=new A.dO(B.Um,2,t.l)
B.Qw=s(["dsl_caterpillar_nfa","dsl_halt_accept_y"],t.s)
B.Yd=new A.hM(B.Qw)
B.MC=new A.aM("pda_balanced_parens","Balanced Parentheses",'Build a PDA over {(, )} that accepts strings with balanced parentheses (e.g. "(()())" accepted, "(()" rejected).\nPush a marker on every "(" and pop it on every ")".',"      pda mode\n      n0 = A\n      n1 = B\n      n0 = (480.0, 360.0)\n      n1 = (820.0, 360.0)\n      n0 is accepted\n      n0 to n0 = (,\u2205|X\n      n0 to n1 = ),X|\u2205\n      n1 to n1 = ),X|\u2205\n      n1 to n0 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aW,null,B.ZJ,B.Yd,0.5,"pda",!1,B.H,null,B.L,"",!1)
B.YE=new A.ca("pda_balanced_parens")
B.Mz=new A.aM("pda_anbn","a\u207fb\u207f","Build a PDA that accepts exactly strings of the form a\u207fb\u207f (n \u2265 1): the same number of a's followed by the same number of b's.\nClassic context-free language \u2014 not recognisable by any DFA!","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|X\n      n0 to n1 = b,X|\u2205\n      n1 to n1 = b,X|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aW,null,B.a5,B.YE,0.5,"pda",!1,B.H,null,B.L,"",!1)
B.YD=new A.ca("pda_anbn")
B.MB=new A.aM("pda_more_as","More a's Than b's","Build a PDA over {a, b} that accepts strings where the number of a's is strictly greater than the number of b's (in any order).\nPush for each a, pop for each b; accept if the stack is non-empty at the end.","      pda mode\n      n0 = A\n      n1 = B\n      n0 = (380.0, 360.0)\n      n1 = (720.0, 360.0)\n      n0 to n0 = a,\u2205|X\n      n0 to n0 = b,X|\u2205\n      n0 to n1 = \u2205,X|X\n      n1 is accepted\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aW,null,B.a5,B.YD,0.5,"pda",!1,B.H,null,B.L,"",!1)
B.YF=new A.ca("pda_more_as")
B.MR=new A.aM("pda_an_b2n","a\u207fb\xb2\u207f","Build a PDA that accepts strings of the form a\u207fb\xb2\u207f (n \u2265 1): for every a there must be exactly two b's.\nHint: push two markers for each a you read.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|X\n      n0 to n0 = a,\u2205|X\n      n0 to n1 = b,X|\u2205\n      n1 to n1 = b,X|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aW,null,B.a5,B.YF,0.5,"pda",!1,B.H,null,B.L,"",!1)
B.D7=new A.ca("pda_an_b2n")
B.Mt=new A.aM("level_2","Level 2 \u2014 PDA Boss","Build a PDA that matches the hidden stack-based target machine. Study the transition format and think carefully about what language this could be.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = <<ha>>\n      n4 = E\n      n5 = F\n      n0 = (723.3, 204.7)\n      n1 = (1139.3, 259.3)\n      n2 = (1196.0, 527.3)\n      n3 = (739.3, 705.3)\n      n4 = (345.3, 504.7)\n      n5 = (345.3, 277.3)\n      n0 to n5 = 0,~|X\n      n0 to n1 = 1,~|Y\n      n1 to n1 = 1,~|Y\n      n1 to n2 = 0,Y|~\n      n2 to n1 = 1,\u2205|Y\n      n2 to n5 = 0,\u2205|X\n      n4 to n1 = 1,\u2205|Y\n      n4 to n5 = 0,\u2205|X\n      n5 to n4 = 1,X|~\n      n5 to n5 = 0,~|X\n      n4 to n4 = 1,X|~\n      n4 to n3 = \u2205,\u2205|~\n      n2 to n3 = \u2205,\u2205|~\n      n2 to n2 = 0,Y|~\n      l0(0,~|X) curve = -2.9\n      l3(0,Y|~) curve = 62.2\n      l4(1,\u2205|Y) curve = 55.1\n      l5(0,\u2205|X) curve = 39.9\n      l6(1,\u2205|Y) curve = 16.9\n      l7(0,\u2205|X) curve = -8.2\n      l8(1,X|~) curve = -105.4\n      l2(1,~|Y) loop angle = -0.7988\n      l9(0,~|X) loop angle = -1.5708\n      l10(1,X|~) loop angle = 1.7686\n      l13(0,Y|~) loop angle = -0.0754\n      to n0 angle = -1.0000, 0.0000\n    ",B.aW,null,B.be,B.D7,0.25,"pda",!1,B.H,null,B.L,"",!1)
B.Me=new A.aM("pda_palindrome","PDA Palindromes","Build a PDA over {a, b} that accepts even-length palindromes (ww^R where w is any string over {a,b}).\nHint: push the first half onto the stack, then pop-match the second half.","      pda mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n0 = (340.0, 360.0)\n      n1 = (680.0, 360.0)\n      n2 = (1020.0, 360.0)\n      n2 is accepted\n      n0 to n0 = a,\u2205|a\n      n0 to n0 = b,\u2205|b\n      n0 to n1 = \u2205,\u2205|\u2205\n      n1 to n1 = a,a|\u2205\n      n1 to n1 = b,b|\u2205\n      n1 to n2 = \u2205,\u2205|\u2205\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.aW,null,B.be,B.D7,0.75,"pda",!1,B.H,null,B.L,"",!1)
B.RA=s(["level_2","pda_palindrome"],t.s)
B.Yg=new A.fN(B.RA)
B.a6h=new A.iA(8,"tmTape")
B.a6o=new A.dy("The Turing Machine","A Turing machine adds a **read/write tape** to a finite automaton. The tape is infinite in both directions and starts with your input.\n\nA **read/write head** sits on one cell at a time. On each step it reads the current symbol, writes a new symbol (or leaves it), and moves **Left** or **Right** (or stays Still).",B.a6h)
B.a6n=new A.dy("TM Transition Format",'Each TM arrow label has the format:\n\n  **readSymbol writeSymbol Direction**\n\nDirection is **R** (right), **L** (left), or **S** (stay).\n\nExample: **"aXR"** \u2014 read "a", write "X", move Right.\nExample: **"\u2205\u2205S"** \u2014 read blank, write blank, stay (blank = empty cell).',B.bE)
B.a6H=new A.dy("Accepting and Rejecting","A TM **accepts** by entering an accept state (double ring) and halting.\n\nA TM **rejects** either by entering a reject state (no outgoing transition for the current symbol causes a crash) or by looping forever.\n\nThe equivalence checker uses a bounded simulation \u2014 it tests many input strings but can't always prove correctness on all inputs.",B.bE)
B.a6z=new A.dy("The Crossout Technique",'Many TM puzzles use a **crossout** strategy:\n\n1. Replace a matched symbol with **X** (or another marker) to "cross it out".\n2. Sweep the tape left/right to find the next unmatched symbol.\n3. Repeat until all symbols are matched or a mismatch is detected.\n\nYou\'ll see this in a\u207fb\u207f, a\u207fb\u207fc\u207f, palindrome, and the "ww" puzzles.',B.bE)
B.a6q=new A.dy("Multiple Loops on One State","TM states often have **many self-loops** \u2014 one for each symbol the machine should pass over without stopping.\n\nIn the canvas you can drag a self-loop's label dot to rotate it around the state circle, so diagrams stay readable even with 4\u20135 loops on one state.",B.bE)
B.Rr=s([B.a6o,B.a6n,B.a6H,B.a6z,B.a6q],t.nY)
B.MX=new A.aM("tutorial_tm","Turing Machines","Learn the read/write tape model and TM transition format.","",B.D,null,B.be,B.Yg,0.5,"tutorial",!0,B.Rr,null,B.L,"",!1)
B.D9=new A.ca("tutorial_tm")
B.ML=new A.aM("tm_identity","TM: Accept All (Trivial)","Build the simplest possible Turing machine: one that accepts every input by halting immediately.\nA single state that is both start and accept will do it. TM transition format: readSymbol writeSymbol Direction (e.g. aBR = read a, write B, move Right).","      tm mode\n      n0 = A\n      A = (600.0, 360.0)\n      A is accepted\n      to A angle = -1.0000, 0.0000\n    ",B.b4,null,B.be,B.D9,0.25,"tm",!1,B.H,null,B.L,"",!1)
B.MG=new A.aM("tm_reject_all","TM: Reject All","Build a TM that loops forever on any non-empty input (rejects by non-halt) and accepts only the empty tape.\nHint: a start state with a self-loop on every symbol that moves right will spin forever.","      tm mode\n      n0 = A\n      n1 = B\n      A = (480.0, 360.0)\n      B = (820.0, 360.0)\n      B is accepted\n      A to B = \u2205\u2205S\n      to A angle = -1.0000, 0.0000\n    ",B.b4,null,B.be,B.D9,0.75,"tm",!1,B.H,null,B.L,"",!1)
B.RK=s(["tm_identity","tm_reject_all"],t.s)
B.Ye=new A.hM(B.RK)
B.N6=new A.aM("tm_anbn","TM: a\u207fb\u207f","Build a TM that accepts exactly strings of the form a\u207fb\u207f (n \u2265 1). Classic TM exercise: repeatedly cross off one a and one b until both sides are exhausted.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      A = (260.0, 200.0)\n      B = (660.0, 200.0)\n      C = (1060.0, 200.0)\n      D = (660.0, 560.0)\n      E = (260.0, 560.0)\n      E is accepted\n      A to B = aXR\n      B to B = aXR\n      B to C = bXL\n      C to D = XXL\n      D to D = aXL\n      D to A = XXR\n      A to E = \u2205\u2205S\n      l1(aXR) loop angle = -1.5708\n      l3(XXL) loop angle = -1.5708\n      l4(aXL) loop angle = 1.5708\n      aXR curve = 80.0\n      bXL curve = 80.0\n      XXR curve = 80.0\n      to A angle = -1.0000, 0.0000\n    ",B.b4,null,B.be,B.Ye,0.5,"tm",!1,B.H,null,B.L,"",!1)
B.YG=new A.ca("tm_anbn")
B.MN=new A.aM("tm_anbncn","TM: a\u207fb\u207fc\u207f","Build a TM that accepts strings of the form a\u207fb\u207fc\u207f (n \u2265 1).\nThis language is not context-free \u2014 no PDA can recognise it \u2014 but a TM can! Cross off one a, one b, and one c per pass.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (580.0, 200.0)\n      C = (900.0, 200.0)\n      D = (900.0, 540.0)\n      E = (580.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      B to B = aaR\n      B to B = XXR\n      B to C = bXR\n      C to C = bbR\n      C to C = XXR\n      C to D = cXL\n      D to D = bbL\n      D to D = ccL\n      D to D = XXL\n      D to E = aaL\n      E to E = aaL\n      E to E = bbL\n      E to E = ccL\n      E to E = XXL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(XXR) loop angle = -0.8000\n      l4(bbR) loop angle = -1.5708\n      l5(XXR) loop angle = -0.8000\n      l7(bbL) loop angle = 1.5708\n      l8(ccL) loop angle = 0.8000\n      l9(XXL) loop angle = 2.3000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.8000\n      l13(ccL) loop angle = 2.3000\n      l14(XXL) loop angle = 3.1000\n      aXR curve = 70.0\n      bXR curve = 70.0\n      cXL curve = 70.0\n      aaL_E curve = 60.0\n      XXR_E curve = 60.0\n      to A angle = -1.0000, 0.0000\n    ",B.b4,null,B.be,B.YG,0.5,"tm",!1,B.H,null,B.L,"",!1)
B.YH=new A.ca("tm_anbncn")
B.Ml=new A.aM("tm_ww","TM: ww (Doubled Word)",'Build a TM that accepts strings of the form ww over {a, b}: a string that consists of some word w repeated exactly twice (e.g. "abab", "aabb aabb"). This is a classic non-context-free language.',"      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 180.0)\n      B = (660.0, 180.0)\n      C = (1060.0, 180.0)\n      D = (1060.0, 540.0)\n      E = (660.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to D = bXL\n      C to C = aaR\n      C to C = bbR\n      C to E = aXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.8000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.8000\n      l7(aaL) loop angle = 1.5708\n      l8(bbL) loop angle = 0.8000\n      l10(aaL) loop angle = 1.5708\n      l11(bbL) loop angle = 0.8000\n      aXR curve = 60.0\n      bXR curve = -60.0\n      bXL curve = 60.0\n      aXL curve = -60.0\n      XXR_D curve = 80.0\n      XXR_E curve = -80.0\n      to A angle = -1.0000, 0.0000\n    ",B.b4,null,B.be,B.YH,0.5,"tm",!1,B.H,null,B.L,"",!1)
B.YJ=new A.ca("tm_ww")
B.Mp=new A.aM("tm_palindrome","TM: Palindrome","Build a TM over {a, b} that accepts palindromes of any length.\nStrategy: repeatedly peel the first and last character and verify they match.","      tm mode\n      n0 = A\n      n1 = B\n      n2 = C\n      n3 = D\n      n4 = E\n      n5 = F\n      A = (260.0, 200.0)\n      B = (640.0, 200.0)\n      C = (1020.0, 200.0)\n      D = (1020.0, 540.0)\n      E = (640.0, 540.0)\n      F = (260.0, 540.0)\n      F is accepted\n      A to B = aXR\n      A to C = bXR\n      B to B = aaR\n      B to B = bbR\n      B to E = aXL\n      C to C = aaR\n      C to C = bbR\n      C to D = bXL\n      D to D = aaL\n      D to D = bbL\n      D to A = XXR\n      E to E = aaL\n      E to E = bbL\n      E to A = XXR\n      A to F = \u2205\u2205S\n      l1(aaR) loop angle = -1.5708\n      l2(bbR) loop angle = -0.6000\n      l5(aaR) loop angle = -1.5708\n      l6(bbR) loop angle = -0.6000\n      l8(aaL) loop angle = 1.5708\n      l9(bbL) loop angle = 0.6000\n      l11(aaL) loop angle = 1.5708\n      l12(bbL) loop angle = 0.6000\n      aXR curve = 70.0\n      bXR curve = -70.0\n      aXL curve = -70.0\n      bXL curve = 70.0\n      to A angle = -1.0000, 0.0000\n    ",B.b4,null,B.be,B.YJ,0.5,"tm",!1,B.H,null,B.L,"",!1)
B.YI=new A.ca("tm_palindrome")
B.a6p=new A.dy("What is a Regular Expression?",'A **regular expression** (regex) is a compact notation for describing a regular language \u2014 the same class of languages recognised by DFAs and NFAs.\n\nOperators used in these puzzles:\n\u2022 **a** \u2014 literal symbol "a"\n\u2022 **ab** \u2014 concatenation (a then b)\n\u2022 **a+b** \u2014 alternation / union (a OR b)\n\u2022 **a*** \u2014 Kleene star (zero or more a)\n\u2022 **(\u2026)** \u2014 grouping',B.bE)
B.a6D=new A.dy("Regex \u2194 Automaton","Every regular expression describes exactly the same set of strings as some DFA (and vice versa). This is why they are called *regular* languages.\n\nThis section has two challenge types:\n\n**Regex \u2192 DFA** \u2014 You are given a regex and must build a DFA whose language matches it exactly.\n\n**DFA \u2192 Regex** \u2014 You are shown a read-only DFA diagram and must type a regex that describes the same language.",B.bE)
B.a6v=new A.dy("Notation Reference",'The checker uses the following notation:\n\n\u2022 **~** \u2014 empty string \u03b5  (e.g. a+~ means "a or nothing")\n\u2022 **\u2205** \u2014 empty language (matches nothing)\n\u2022 **+** \u2014 alternation  (a+b means a OR b)\n\u2022 ***** \u2014 Kleene star, postfix  (a* = zero or more a)\n\u2022 Concatenation is implicit: **ab** means a then b\n\nPrecedence (high\u2192low): star \u2192 concat \u2192 union.\nUse parentheses to override: (a+b)* = any string over {a,b}.',B.bE)
B.a6u=new A.dy("Tips: Regex \u2192 DFA",'When you see a regex, ask: "what pattern must a string satisfy?"\n\n\u2022 **ab*** \u2014 any number of b\'s after exactly one a\n\u2022 **(a+b)*abb** \u2014 anything, ending in "abb"\n\u2022 **(ab)*** \u2014 alternating pairs: \u03b5, ab, abab, \u2026\n\nThink about what the machine must *remember*. Each memory unit (e.g. "last symbol seen") usually becomes a state.',B.bE)
B.a6k=new A.dy("Tips: DFA \u2192 Regex","To derive a regex from a DFA, try **state elimination**:\n\n1. Add a super-start \u2192 original start and all accept states \u2192 super-accept with \u03b5-transitions.\n2. Remove inner states one by one, merging their transitions into regex labels on the remaining edges.\n3. The final label on the super-start \u2192 super-accept edge is your regex.\n\nIn practice, pattern recognition is often faster: spot self-loops (\u2192 *), linear paths (\u2192 concat), branches (\u2192 +).",B.bE)
B.RB=s([B.a6p,B.a6D,B.a6v,B.a6u,B.a6k],t.nY)
B.Na=new A.aM("tutorial_regex","Regular Expressions","Learn the connection between regular expressions and finite automata.","",B.D,null,B.be,B.YI,0.5,"tutorial",!0,B.RB,null,B.L,"",!1)
B.nJ=new A.ca("tutorial_regex")
B.eq=new A.EF(1,"regexToDfa")
B.MV=new A.aM("regex_to_dfa_ab_star","Regex \u2192 DFA: ab*",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    ab*\n\nMatches "a" followed by any number of b\'s: "a", "ab", "abb", "abbb", \u2026',"      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 580.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n1 = b\n      n1 to n2 = a\n      n2 to n2 = a,b\n      l2(b) loop angle = -1.5708\n      l4(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.az,B.a5,B.nJ,0.2,"regex",!1,B.H,null,B.eq,"ab*",!1)
B.Mx=new A.aM("regex_to_dfa_starts_a","Regex \u2192 DFA: a(a+b)*",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    a(a+b)*\n\nMatches all strings that start with "a": "a", "aa", "ab", "aba", \u2026',"      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 580.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n1 = a,b\n      n2 to n2 = a,b\n      l2(a,b) loop angle = -1.5708\n      l3(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.az,B.a5,B.nJ,0.5,"regex",!1,B.H,null,B.eq,"a(a+b)*",!1)
B.ME=new A.aM("regex_to_dfa_ends_b","Regex \u2192 DFA: (a+b)*b",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    (a+b)*b\n\nMatches all strings that end with "b": "b", "ab", "bb", "aab", \u2026',u.C,B.D,B.az,B.a5,B.nJ,0.8,"regex",!1,B.H,null,B.eq,"(a+b)*b",!1)
B.Pg=s(["regex_to_dfa_ab_star","regex_to_dfa_starts_a","regex_to_dfa_ends_b"],t.s)
B.nG=new A.fN(B.Pg)
B.MU=new A.aM("regex_to_dfa_a_or_b_star","Regex \u2192 DFA: (a+b)*","Build a DFA over {a, b} equivalent to the regular expression:\n\n    (a+b)*\n\nMatches every string over {a, b} \u2014 including the empty string \u03b5.","      n0 = q0\n      n0 = (600.0, 360.0)\n      n0 is accepted\n      n0 to n0 = a,b\n      a,b loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.az,B.a5,B.nG,0.2,"regex",!1,B.H,null,B.eq,"(a+b)*",!1)
B.N_=new A.aM("regex_to_dfa_aba","Regex \u2192 DFA: (a+b)*aba(a+b)*",'Build a DFA over {a, b} equivalent to the regular expression:\n\n    (a+b)*aba(a+b)*\n\nMatches all strings containing "aba" as a substring.',"      n0 = q0\n      n1 = q1\n      n2 = q2\n      n3 = q3\n      n0 = (280.0, 360.0)\n      n1 = (580.0, 360.0)\n      n2 = (880.0, 360.0)\n      n3 = (1180.0, 360.0)\n      n3 is accepted\n      n0 to n1 = a\n      n0 to n0 = b\n      n1 to n1 = a\n      n1 to n2 = b\n      n2 to n3 = a\n      n3 to n3 = a,b\n      n2 to n0 = b\n      l0(b) loop angle = -1.5708\n      l2(a) loop angle = -1.5708\n      l5(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,B.az,B.a5,B.nG,0.5,"regex",!1,B.H,null,B.eq,"(a+b)*aba(a+b)*",!1)
B.N9=new A.aM("regex_to_dfa_even_as","Regex \u2192 DFA: b*(ab*ab*)*","Build a DFA over {a, b} equivalent to the regular expression:\n\n    b*(ab*ab*)*\n\nMatches all strings with an even number of a's (including zero a's).",u.m,B.D,B.az,B.a5,B.nG,0.8,"regex",!1,B.H,null,B.eq,"b*(ab*ab*)*",!1)
B.Rq=s(["regex_to_dfa_a_or_b_star","regex_to_dfa_aba","regex_to_dfa_even_as"],t.s)
B.nH=new A.fN(B.Rq)
B.d9=new A.EF(2,"dfaToRegex")
B.MK=new A.aM("dfa_to_regex_single_a",'DFA \u2192 Regex: Accept "a"','A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts only the single-character string "a".',"      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (320.0, 360.0)\n      n1 = (660.0, 360.0)\n      n2 = (660.0, 580.0)\n      n1 is accepted\n      n0 to n1 = a\n      n0 to n2 = b\n      n1 to n2 = a,b\n      n2 to n2 = a,b\n      l3(a,b) loop angle = -1.5708\n      l2(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.a5,B.nH,0.2,"regex",!1,B.H,null,B.d9,"a",!1)
B.Mw=new A.aM("dfa_to_regex_ends_b","DFA \u2192 Regex: Ends with b",'A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} that end with "b".',u.C,B.D,null,B.a5,B.nH,0.5,"regex",!1,B.H,null,B.d9,"(a+b)*b",!1)
B.Mn=new A.aM("dfa_to_regex_even_as","DFA \u2192 Regex: Even a's","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} with an even number of a's.",u.m,B.D,null,B.a5,B.nH,0.8,"regex",!1,B.H,null,B.d9,"b*(ab*ab*)*",!1)
B.QK=s(["dfa_to_regex_single_a","dfa_to_regex_ends_b","dfa_to_regex_even_as"],t.s)
B.nI=new A.fN(B.QK)
B.MY=new A.aM("dfa_to_regex_starts_ab","DFA \u2192 Regex: Starts with ab",'A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} that start with "ab".',"      n0 = q0\n      n1 = q1\n      n2 = q2\n      n3 = dead\n      n0 = (240.0, 360.0)\n      n1 = (560.0, 360.0)\n      n2 = (880.0, 360.0)\n      n3 = (560.0, 600.0)\n      n2 is accepted\n      n0 to n1 = a\n      n0 to n3 = b\n      n1 to n2 = b\n      n1 to n3 = a\n      n2 to n2 = a,b\n      n3 to n3 = a,b\n      l4(a,b) loop angle = -1.5708\n      l5(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.a5,B.nI,0.2,"regex",!1,B.H,null,B.d9,"ab(a+b)*",!1)
B.Nc=new A.aM("dfa_to_regex_no_consec_b","DFA \u2192 Regex: No Consecutive b's","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} containing no two consecutive b's.","      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (400.0, 340.0)\n      n1 = (780.0, 340.0)\n      n2 = (580.0, 580.0)\n      n0 is accepted\n      n1 is accepted\n      n0 to n1 = b\n      n0 to n0 = a\n      n1 to n0 = a\n      n1 to n2 = b\n      n2 to n2 = a,b\n      l0(a) loop angle = -1.5708\n      l4(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.a5,B.nI,0.5,"regex",!1,B.H,null,B.d9,"a*(ba+)*b?",!1)
B.MI=new A.aM("dfa_to_regex_binary_mod2","DFA \u2192 Regex: Even 0s","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts binary strings over {0, 1} with an even number of 0s.","      n0 = even\n      n1 = odd\n      n0 = (504.7, 310.0)\n      n1 = (1030.0, 314.0)\n      n0 is accepted\n      n0 to n1 = 0\n      n1 to n0 = 0\n      n0 to n0 = 1\n      n1 to n1 = 1\n      l0(0) curve = -74.1\n      l1(0) curve = -72.7\n      l2(1) loop angle = -1.5708\n      l3(1) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.D,null,B.cP,B.nI,0.8,"regex",!1,B.H,null,B.d9,"1*(01*01*)*",!1)
